#include <iostream>
#include <iomanip>
using namespace std;

int main() {
    long long G, M, D;
    cin >> G;
    cin >> M;

    long long total = 0;
    for (int i = 0; i < M; i++) {
        long long w;
        cin >> w;
        total += w;
    }

    cin >> D;
    total -= D;

    long long nisab = 85 * G;

    if (total < nisab) {
        cout << "No Zakat required";
        return 0;
    }

    double zakat = total * 0.025;
    cout << fixed << setprecision(2);
    cout << "Zakat: " << zakat;
}
